proof_block:
reveal(StrictlyOrderedVec::valid);
K::cmp_properties();

if post1_self_.valid()
    && post1_self_@.len() == pre_self_@.len() + 1
    && 0 <= (r1 as int) && (r1 as int) < post1_self_@.len()
    && post1_self_@ == pre_self_@.insert(r1 as int, k)
    && post2_self_.valid()
    && post2_self_@.len() == pre_self_@.len() + 1
    && 0 <= (r2 as int) && (r2 as int) < post2_self_@.len()
    && post2_self_@ == pre_self_@.insert(r2 as int, k)
{
    let ri1: int = r1 as int;
    let ri2: int = r2 as int;
    let s = pre_self_@;
    let p1 = post1_self_@;
    let p2 = post2_self_@;

    // From the ensures: p1 = s.insert(ri1, k) and p2 = s.insert(ri2, k).
    // Both have length s.len() + 1, so 0 <= ri1, ri2 <= s.len().
    assert(p1.len() == s.len() + 1);
    assert(p2.len() == s.len() + 1);
    assert(ri1 <= s.len() as int);
    assert(ri2 <= s.len() as int);

    if ri1 < ri2 {
        // ri1 < ri2 <= s.len(), so ri1 < s.len() and ri1 + 1 <= s.len() < p1.len().
        assert(ri1 < s.len() as int);
        assert(ri1 + 1 < p1.len() as int);

        // Seq::insert axioms:
        //   p1 = s.insert(ri1, k) gives p1[ri1] == k and p1[ri1+1] == s[ri1].
        assert(p1[ri1] == k);
        assert(p1[ri1 + 1] == s[ri1]);
        //   p2 = s.insert(ri2, k), with ri1 < ri2, gives p2[ri1] == s[ri1]; also p2[ri2] == k.
        assert(p2[ri1] == s[ri1]);
        assert(p2[ri2] == k);

        // sorted(p1) at (ri1, ri1+1):  p1[ri1].cmp_spec(p1[ri1+1]).lt()  =>  k.cmp_spec(s[ri1]).lt()
        assert(p1[ri1].cmp_spec(p1[ri1 + 1]).lt());
        assert(k.cmp_spec(s[ri1]).lt());
        // sorted(p2) at (ri1, ri2):    p2[ri1].cmp_spec(p2[ri2]).lt()    =>  s[ri1].cmp_spec(k).lt()
        assert(p2[ri1].cmp_spec(p2[ri2]).lt());
        assert(s[ri1].cmp_spec(k).lt());

        // K::cmp_properties: a.cmp_spec(b).lt() <==> b.cmp_spec(a).gt().
        // Hence k.cmp_spec(s[ri1]) is simultaneously Less and Greater — impossible.
        assert(s[ri1].cmp_spec(k).lt() <==> k.cmp_spec(s[ri1]).gt());
        assert(k.cmp_spec(s[ri1]).gt());
        assert(k.cmp_spec(s[ri1]).lt());
        assert(false);
    } else if ri2 < ri1 {
        // Symmetric case.
        assert(ri2 < s.len() as int);
        assert(ri2 + 1 < p2.len() as int);

        assert(p2[ri2] == k);
        assert(p2[ri2 + 1] == s[ri2]);
        assert(p1[ri2] == s[ri2]);
        assert(p1[ri1] == k);

        assert(p2[ri2].cmp_spec(p2[ri2 + 1]).lt());
        assert(k.cmp_spec(s[ri2]).lt());
        assert(p1[ri2].cmp_spec(p1[ri1]).lt());
        assert(s[ri2].cmp_spec(k).lt());

        assert(s[ri2].cmp_spec(k).lt() <==> k.cmp_spec(s[ri2]).gt());
        assert(k.cmp_spec(s[ri2]).gt());
        assert(k.cmp_spec(s[ri2]).lt());
        assert(false);
    }

    // Both r1 < r2 and r2 < r1 are infeasible, so r1 == r2.
    assert(!(ri1 < ri2));
    assert(!(ri2 < ri1));
    assert(ri1 == ri2);
    assert(r1 == r2);

    // Function congruence on Seq::insert: same s, same index, same k -> same Seq.
    assert(s.insert(ri1, k) == s.insert(ri2, k));
    assert(post1_self_@ == post2_self_@);
}
